class Solution {
public:
    int maxSatisfied(vector<int>& customers, vector<int>& grumpy, int minutes) {
        int total = 0, maxExtra = 0;
        for (int i = 0; i < customers.size(); i++) {
            if (grumpy[i] == 0) {
                total += customers[i];
            } else {
                maxExtra += customers[i];
            }
        }
        for (int i = 0; i < customers.size() - minutes; i++) {
            maxExtra = max(maxExtra, customers[i + minutes] + customers[i + minutes - 1] + ... + customers[i]);
        }
        return total + min(maxExtra, total);
    }
};
```
